// MARK: - Session Delegate for SSL/TLS Handling

final class NetworkSessionDelegate: NSObject, URLSessionDelegate, URLSessionTaskDelegate, @unchecked Sendable {
    
    private let allowedInsecureHosts: Set<String>
    private let lock = NSLock()
    private var _trustedLocalHosts: Set<String> = []
    
    var trustedLocalHosts: Set<String> {
        get {
            lock.lock()
            defer { lock.unlock() }
            return _trustedLocalHosts
        }
        set {
            lock.lock()
            defer { lock.unlock() }
            _trustedLocalHosts = newValue
        }
    }
    
    override init() {
        self.allowedInsecureHosts = []
        super.init()
    }
    
    init(allowedInsecureHosts: Set<String> = []) {
        self.allowedInsecureHosts = allowedInsecureHosts
        super.init()
    }
    
    func addTrustedLocalHost(_ host: String) {
        guard LocalNetworkPolicy.isLocalNetworkAddress(host) else {
            return
        }
        lock.lock()
        defer { lock.unlock() }
        _trustedLocalHosts.insert(host)
    }
    
    func removeTrustedLocalHost(_ host: String) {
        lock.lock()
        defer { lock.unlock() }
        _trustedLocalHosts.remove(host)
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        handleChallenge(challenge, completionHandler: completionHandler)
    }
    
    func urlSession(
        _ session: URLSession,
        task: URLSessionTask,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        handleChallenge(challenge, completionHandler: completionHandler)
    }
    
    private func handleChallenge(
        _ challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        let protectionSpace = challenge.protectionSpace
        let host = protectionSpace.host
        
        guard protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // For cloud API: perform certificate pinning
        if let pins = CertificatePinningConfig.pinnedDomains[host] {
            handleCloudCertificateValidation(
                serverTrust: serverTrust,
                host: host,
                pins: pins,
                completionHandler: completionHandler
            )
            return
        }
        
        // For local network devices: allow self-signed certificates only for known local IPs
        if LocalNetworkPolicy.isLocalNetworkAddress(host) {
            let currentTrustedHosts = trustedLocalHosts
            if currentTrustedHosts.contains(host) || allowedInsecureHosts.contains(host) {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                return
            }
        }
        
        // Default: use system validation
        completionHandler(.performDefaultHandling, nil)
    }
    
    private func handleCloudCertificateValidation(
        serverTrust: SecTrust,
        host: String,
        pins: [String],
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        // Evaluate the server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Check certificate pinning
        guard verifyCertificatePinning(serverTrust: serverTrust, pins: pins) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
    
    private func verifyCertificatePinning(serverTrust: SecTrust, pins: [String]) -> Bool {
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        
        guard certificateCount > 0 else {
            return false
        }
        
        if #available(iOS 15.0, *) {
            guard let certificateChain = SecTrustCopyCertificateChain(serverTrust) as? [SecCertificate],
                  let serverCertificate = certificateChain.first else {
                return false
            }
            return verifyCertificatePin(certificate: serverCertificate, pins: pins)
        } else {
            guard let serverCertificate = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
                return false
            }
            return verifyCertificatePin(certificate: serverCertificate, pins: pins)
        }
    }
    
    private func verifyCertificatePin(certificate: SecCertificate, pins: [String]) -> Bool {
        guard let publicKey = SecCertificateCopyKey(certificate) else {
            return false
        }
        
        guard let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, nil) as Data? else {
            return false
        }
        
        let hash = sha256Hash(data: publicKeyData)
        let hashBase64 = hash.base64EncodedString()
        
        return pins.contains(hashBase64)
    }
    
    private func sha256Hash(data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
}

