// MARK: - HTTP Client Protocol

protocol HTTPClientProtocol {
    func send<T: Decodable>(
        _ configuration: RequestConfiguration,
        responseType: T.Type
    ) async throws -> T
    
    func sendRaw(_ configuration: RequestConfiguration) async throws -> (Data, HTTPURLResponse)
}

// MARK: - HTTP Client

final class HTTPClient: HTTPClientProtocol {
    
    private let cloudSession: URLSession
    private let localDeviceSession: URLSession
    private let sessionDelegate: NetworkSessionDelegate
    private let jsonDecoder: JSONDecoder
    private let rateLimiter: RateLimiter
    
    init(
        allowedInsecureLocalHosts: Set<String> = [],
        cloudTimeoutInterval: TimeInterval = 30,
        localTimeoutInterval: TimeInterval = 10
    ) {
        self.sessionDelegate = NetworkSessionDelegate(allowedInsecureHosts: allowedInsecureLocalHosts)
        self.jsonDecoder = JSONDecoder()
        self.jsonDecoder.dateDecodingStrategy = .iso8601
        self.rateLimiter = RateLimiter(maxRequestsPerSecond: 50)
        
        // Cloud session configuration - strict security
        let cloudConfig = URLSessionConfiguration.default
        cloudConfig.timeoutIntervalForRequest = cloudTimeoutInterval
        cloudConfig.timeoutIntervalForResource = cloudTimeoutInterval * 2
        cloudConfig.tlsMinimumSupportedProtocolVersion = .TLSv12
        cloudConfig.httpShouldSetCookies = false
        cloudConfig.httpCookieAcceptPolicy = .never
        cloudConfig.requestCachePolicy = .reloadIgnoringLocalCacheData
        cloudConfig.urlCache = nil
        
        self.cloudSession = URLSession(
            configuration: cloudConfig,
            delegate: sessionDelegate,
            delegateQueue: nil
        )
        
        // Local device session configuration - relaxed for IoT compatibility
        let localConfig = URLSessionConfiguration.default
        localConfig.timeoutIntervalForRequest = localTimeoutInterval
        localConfig.timeoutIntervalForResource = localTimeoutInterval * 2
        localConfig.tlsMinimumSupportedProtocolVersion = .TLSv10
        localConfig.httpShouldSetCookies = false
        localConfig.httpCookieAcceptPolicy = .never
        localConfig.requestCachePolicy = .reloadIgnoringLocalCacheData
        localConfig.urlCache = nil
        
        self.localDeviceSession = URLSession(
            configuration: localConfig,
            delegate: sessionDelegate,
            delegateQueue: nil
        )
    }
    
    deinit {
        cloudSession.invalidateAndCancel()
        localDeviceSession.invalidateAndCancel()
    }
    
    // MARK: - Public API
    
    func send<T: Decodable>(
        _ configuration: RequestConfiguration,
        responseType: T.Type
    ) async throws -> T {
        let (data, _) = try await sendRaw(configuration)
        
        do {
            let decoded = try jsonDecoder.decode(T.self, from: data)
            return decoded
        } catch {
            throw NetworkError.decodingError(error)
        }
    }
    
    func sendRaw(_ configuration: RequestConfiguration) async throws -> (Data, HTTPURLResponse) {
        let request = try buildRequest(from: configuration)
        
        // Validate the request
        try validateRequest(request, environment: configuration.environment)
        
        // Rate limiting
        try await rateLimiter.waitForPermission()
        
        let session = sessionForEnvironment(configuration.environment)
        
        let (data, response): (Data, URLResponse)
        do {
            (data, response) = try await session.data(for: request)
        } catch let urlError as URLError {
            switch urlError.code {
            case .timedOut:
                throw NetworkError.timeout
            case .notConnectedToInternet, .networkConnectionLost:
                throw NetworkError.networkUnavailable
            case .serverCertificateUntrusted, .serverCertificateHasBadDate,
                 .serverCertificateHasUnknownRoot, .serverCertificateNotYetValid:
                throw NetworkError.untrustedConnection(request.url?.host ?? "unknown")
            default:
                throw NetworkError.unknown(urlError)
            }
        } catch {
            throw NetworkError.unknown(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.invalidResponse
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw NetworkError.httpError(statusCode: httpResponse.statusCode, data: data)
        }
        
        return (data, httpResponse)
    }
    
    // MARK: - Convenience Methods
    
    func get<T: Decodable>(
        _ url: String,
        headers: [String: String]? = nil,
        environment: NetworkEnvironment = .cloud,
        responseType: T.Type
    ) async throws -> T {
        let config = RequestConfiguration(
            url: url,
            method: .get,
            headers: headers,
            environment: environment
        )
        return try await send(config, responseType: responseType)
    }
    
    func post<T: Decodable, B: Encodable>(
        _ url: String,
        body: B,
        headers: [String: String]? = nil,
        environment: NetworkEnvironment = .cloud,
        responseType: T.Type
    ) async throws -> T {
        let bodyData = try JSONEncoder().encode(body)
        var allHeaders = headers ?? [:]
        allHeaders["Content-Type"] = "application/json"
        
        let config = RequestConfiguration(
            url: url,
            method: .post,
            headers: allHeaders,
            body: bodyData,
            environment: environment
        )
        return try await send(config, responseType: responseType)
    }
    
    // MARK: - Local Device Methods
    
    func trustLocalDevice(host: String) {
        sessionDelegate.addTrustedLocalHost(host)
    }
    
    func untrustLocalDevice(host: String) {
        sessionDelegate.removeTrustedLocalHost(host)
    }
    
    func discoverLocalDevice<T: Decodable>(
        ip: String,
        port: Int = 80,
        path: String = "/info",
        responseType: T.Type
    ) async throws -> T {
        guard LocalNetworkPolicy.isLocalNetworkAddress(ip) else {
            throw NetworkError.invalidURL
        }
        
        let url = "http://\(ip):\(port)\(path)"
        let config = RequestConfiguration(
            url: url,
            method: .get,
            timeoutInterval: 5,
            environment: .localDevice
        )
        return try await send(config, responseType: responseType)
    }
    
    // MARK: - Private Methods
    
    private func buildRequest(from configuration: RequestConfiguration) throws -> URLRequest {
        let urlString: String
        switch configuration.environment {
        case .cloud:
            if configuration.url.hasPrefix("http") {
                urlString = configuration.url
            } else {
                urlString = "\(NetworkEnvironment.cloud.baseURL)\(configuration.url)"
            }
        case .localDevice:
            urlString = configuration.url
        }
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = configuration.method.rawValue
        request.timeoutInterval = configuration.timeoutInterval
        
        // Set default headers
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue("IoTClient/1.0", forHTTPHeaderField: "User-Agent")
        
        // Add auth token for cloud requests
        if configuration.environment == .cloud,
           let token = AuthTokenManager.shared.accessToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        // Add custom headers
        configuration.headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        // Set body
        if let body = configuration.body {
            request.httpBody = body
        }
        
        return request
    }
    
    private func validateRequest(_ request: URLRequest, environment: NetworkEnvironment) throws {
        guard let url = request.url,
              let host = url.host,
              let scheme = url.scheme else {
            throw NetworkError.invalidURL
        }
        
        switch environment {
        case .cloud:
            // Cloud requests MUST use HTTPS
            guard scheme == "https" else {
                throw NetworkError.untrustedConnection(host)
            }
        case .localDevice:
            // Local device requests must target private network addresses
            guard LocalNetworkPolicy.isLocalNetworkAddress(host) else {
                // If it's not a local address, it must use HTTPS
                guard scheme == "https" else {
                    throw NetworkError.untrustedConnection(host)
                }
            }
            // HTTP is allowed only for verified local network addresses
        }
    }
    
    private func sessionForEnvironment(_ environment: NetworkEnvironment) -> URLSession {
        switch environment {
        case .cloud:
            return cloudSession
        case .localDevice:
            return localDeviceSession
        }
    }
}

// MARK: - Rate Limiter

actor RateLimiter {
    private let maxRequestsPerSecond: Int
    private var requestTimestamps: [Date] = []
    
    init(maxRequestsPerSecond: Int) {
        self.maxRequestsPerSecond = maxRequestsPerSecond
    }
    
    func waitForPermission() async throws {
        let now = Date()
        let windowStart = now.addingTimeInterval(-1.0)
        
        // Remove timestamps outside the window
        requestTimestamps = requestTimestamps.filter { $0 > windowStart }
        
        if requestTimestamps.count >= maxRequestsPerSecond {
            guard let oldestInWindow = requestTimestamps.first else { return }
            let waitTime = oldestInWindow.timeIntervalSince(windowStart)
            if waitTime > 0 {
                try await Task.sleep(nanoseconds: UInt64(waitTime * 1_000_000_000))
            }
        }
        
        requestTimestamps.append(Date())
    }
}

