import CommonCrypto

// MARK: - Example Models

struct DeviceInfo: Codable {
    let id: String
    let name: String
    let firmwareVersion: String
    let status: String
}

struct CloudAPIResponse<T: Codable>: Codable {
    let success: Bool
    let data: T?
    let error: String?
}

struct DeviceCommand: Codable {
    let action: String
    let parameters: [String: String]?
}

struct DeviceCommandResponse: Codable {
    let success: Bool
    let message: String?
}

// MARK: - IoT Device Manager

final class IoTDeviceManager {
    
    private let httpClient: HTTPClient
    
    init(httpClient: HTTPClient) {
        self.httpClient = httpClient
    }
    
    // Discover a device on the local network
    func discoverDevice(ip: String, port: Int = 80) async throws -> DeviceInfo {
        return try await httpClient.discoverLocalDevice(
            ip: ip,
            port: port,
            path: "/api/info",
            responseType: DeviceInfo.self
        )
    }
    
    // Send command to local device
    func sendCommand(
        to deviceIP: String,
        port: Int = 80,
        command: DeviceCommand
    ) async throws -> DeviceCommandResponse {
        guard LocalNetworkPolicy.isLocalNetworkAddress(deviceIP) else {
            throw NetworkError.invalidURL
        }
        
        let bodyData = try JSONEncoder().encode(command)
        let config = RequestConfiguration(
            url: "http://\(deviceIP):\(port)/api/command",
            method: .post,
            headers: ["Content-Type": "application/json"],
            body: bodyData,
            timeoutInterval: 10,
            environment: .localDevice
        )
        
        return try await httpClient.send(config, responseType: DeviceCommandResponse.self)
    }
    
    // Register device with cloud
    func registerDeviceWithCloud(deviceInfo: DeviceInfo) async throws -> CloudAPIResponse<DeviceInfo> {
        return try await httpClient.post(
            "/api/v1/devices/register",
            body: deviceInfo,
            environment: .cloud,
            responseType: CloudAPIResponse<DeviceInfo>.self
        )
    }
    
    // Get device list from cloud
    func getCloudDevices() async throws -> CloudAPIResponse<[DeviceInfo]> {
        return try await httpClient.get(
            "/api/v1/devices",
            environment: .cloud,
            responseType: CloudAPIResponse<[DeviceInfo]>.self
        )
    }
    
    // Scan local network for devices
    func scanLocalNetwork(
        subnet: String = "192.168.1",
        port: Int = 80,
        range: ClosedRange<Int> = 1...254
    ) async -> [DeviceInfo] {
        guard LocalNetworkPolicy.isLocalNetworkAddress("\(subnet).1") else {
            return []
        }
        
        var discoveredDevices: [DeviceInfo] = []
        
        await withTaskGroup(of: DeviceInfo?.self) { group in
            for i in range {
                let ip = "\(subnet).\(i)"
                group.addTask { [weak self] in
                    try? await self?.discoverDevice(ip: ip, port: port)
                }
            }
            
            for await device in group {
                if let device = device {
                    discoveredDevices.append(device)
                }
            }
        }
        
        return discoveredDevices
    }
}

// MARK: - Usage Example

/*
 
 // Info.plist must include:
 // NSAppTransportSecurity -> NSAllowsLocalNetworking = YES
 // NSAppTransportSecurity -> NSExceptionDomains -> (specific local domains if needed)
 // NSLocalNetworkUsageDescription = "This app needs to discover and communicate with IoT devices on your local network."
 // NSBonjourServices (if using Bonjour discovery)
 
 // Initialize the HTTP client
 let httpClient = HTTPClient(
     allowedInsecureLocalHosts: ["192.168.1.100", "192.168.1.101"]
 )
 
 // Set auth token for cloud API
 AuthTokenManager.shared.accessToken = "your-jwt-token-here"
 
 // Initialize device manager
 let deviceManager = IoTDeviceManager(httpClient: httpClient)
 
 // Trust a new local device (for self-signed HTTPS)
 httpClient.trustLocalDevice(host: "192.168.1.50")
 
 // Discover a specific device
 Task {
     do {
         let device = try await deviceManager.discoverDevice(ip: "192.168.1.100")
         print("Found device: \(device.name)")
         
         // Send a command
         let command = DeviceCommand(action: "toggle", parameters: ["state": "on"])
         let response = try await deviceManager.sendCommand(
             to: "192.168.1.100",
             command: command
         )
         print("Command result: \(response.message ?? "OK")")
         
         // Register with cloud
         let cloudResponse = try await deviceManager.registerDeviceWithCloud(deviceInfo: device)
         print("Cloud registration: \(cloudResponse.success)")
         
     } catch {
         print("Error: \(error)")
     }
 }
 
 // Scan local network
 Task {
     let devices = await deviceManager.scanLocalNetwork(subnet: "192.168.1")
     print("Found \(devices.count) devices on local network")
 }
 
 */